  `weight_condition` varchar(200) DEFAULT NULL COMMENT '权重表达式如：0.4;n<0:0.2;n<n*0.3:0.2;n>2*avg:1.2(tag;n<0:0.1;n>2*avg:0.8)',
  `remark` varchar(500) DEFAULT NULL COMMENT '指标备注',
  PRIMARY KEY (`ID`),
  UNIQUE KEY `INDEX_CODE` (`INDEX_CODE`),
  KEY `FK_t_data_diictionary_t_match_info` (`SYSTEM_CHILD_TABLE_CODE`),
